-- ER DIAGRAM DESCRIPTION:
-- STUDENT (student_id PK, name, email)
-- COURSE  (course_id PK, title, credits)
-- INSTRUCTOR (instructor_id PK, name, department)
-- ENROLLMENT (student_id FK, course_id FK, grade) — many-to-many junction
-- TEACHES    (instructor_id FK, course_id FK)       — many-to-many junction

CREATE TABLE student (
  student_id   INT PRIMARY KEY,
  name         VARCHAR(60),
  email        VARCHAR(80) UNIQUE
);

CREATE TABLE course (
  course_id  INT PRIMARY KEY,
  title      VARCHAR(100),
  credits    INT
);

CREATE TABLE instructor (
  instructor_id INT PRIMARY KEY,
  name          VARCHAR(60),
  department    VARCHAR(60)
);

CREATE TABLE enrollment (
  student_id INT,
  course_id  INT,
  grade      CHAR(2),
  PRIMARY KEY (student_id, course_id),
  FOREIGN KEY (student_id) REFERENCES student(student_id),
  FOREIGN KEY (course_id)  REFERENCES course(course_id)
);

CREATE TABLE teaches (
  instructor_id INT,
  course_id     INT,
  PRIMARY KEY (instructor_id, course_id),
  FOREIGN KEY (instructor_id) REFERENCES instructor(instructor_id),
  FOREIGN KEY (course_id)     REFERENCES course(course_id)
);

