INSERT INTO teaches     VALUES (1,101),(1,102),(2,103);

-- Query: Which instructor teaches which course?
SELECT i.name AS instructor, c.title AS course
FROM teaches t
JOIN instructor i ON t.instructor_id = i.instructor_id
JOIN course     c ON t.course_id     = c.course_id
ORDER BY i.name;

-- 1. ONE-TO-ONE: Each employee has exactly one employee profile
CREATE TABLE employee (
  emp_id INT PRIMARY KEY,
  name   VARCHAR(50)
);

CREATE TABLE employee_profile (
  profile_id    INT PRIMARY KEY,
  emp_id        INT UNIQUE,   -- UNIQUE ensures one profile per employee
  bio           VARCHAR(200),
  linkedin_url  VARCHAR(100),
  FOREIGN KEY (emp_id) REFERENCES employee(emp_id)
);

-- 2. ONE-TO-MANY: One department has many employees
CREATE TABLE department (
  dept_id INT PRIMARY KEY,
  name    VARCHAR(50)
);

CREATE TABLE dept_employee (
  emp_id  INT PRIMARY KEY,
  name    VARCHAR(50),
  dept_id INT,
  FOREIGN KEY (dept_id) REFERENCES department(dept_id)
);

-- 3. MANY-TO-MANY: Students enroll in many courses, courses have many students
CREATE TABLE uni_student (student_id INT PRIMARY KEY, name VARCHAR(50));
CREATE TABLE uni_course  (course_id  INT PRIMARY KEY, title VARCHAR(80));
CREATE TABLE uni_enrollment (
  student_id INT, course_id INT,
  PRIMARY KEY (student_id, course_id),
  FOREIGN KEY (student_id) REFERENCES uni_student(student_id),
  FOREIGN KEY (course_id)  REFERENCES uni_course(course_id)
);

INSERT INTO employee VALUES (1,'Alice'),(2,'Bob');
INSERT INTO employee_profile VALUES (1,1,'Senior Developer','linkedin.com/alice'),(2,2,'Marketing Lead','linkedin.com/bob');
INSERT INTO department VALUES (10,'Engineering'),(20,'Marketing');
INSERT INTO dept_employee VALUES (101,'Alice',10),(102,'Bob',20),(103,'Carol',10);
INSERT INTO uni_student VALUES (1,'Alice'),(2,'Bob');
