-- Query all three patterns:
SELECT e.name, p.bio FROM employee e JOIN employee_profile p ON e.emp_id = p.emp_id;
SELECT d.name AS dept, COUNT(de.emp_id) AS emp_count FROM department d JOIN dept_employee de ON d.dept_id = de.dept_id GROUP BY d.name;
SELECT s.name, c.title FROM uni_enrollment ue JOIN uni_student s ON ue.student_id = s.student_id JOIN uni_course c ON ue.course_id = c.course_id;

-- LIBRARY ER DESIGN:
-- BOOK (book_id PK, title, isbn UNIQUE, year)
-- MEMBER (member_id PK, name, email UNIQUE, joined_date)
-- AUTHOR (author_id PK, name)
-- LOAN (loan_id PK, member_id FK, book_id FK, loan_date, due_date, returned DATE)
-- BOOK_AUTHOR (book_id FK, author_id FK) — a book can have multiple authors

CREATE TABLE author (author_id INT PRIMARY KEY, name VARCHAR(60));
CREATE TABLE book (
  book_id INT PRIMARY KEY,
  title   VARCHAR(120),
  isbn    VARCHAR(20) UNIQUE,
  year    INT
);
CREATE TABLE book_author (
  book_id INT, author_id INT,
  PRIMARY KEY (book_id, author_id),
  FOREIGN KEY (book_id)   REFERENCES book(book_id),
  FOREIGN KEY (author_id) REFERENCES author(author_id)
);
CREATE TABLE member (
  member_id   INT PRIMARY KEY,
  name        VARCHAR(60),
  email       VARCHAR(80) UNIQUE,
  joined_date DATE
);
CREATE TABLE loan (
  loan_id    INT PRIMARY KEY,
  member_id  INT,
  book_id    INT,
  loan_date  DATE,
  due_date   DATE,
  returned   DATE,
  FOREIGN KEY (member_id) REFERENCES member(member_id),
  FOREIGN KEY (book_id)   REFERENCES book(book_id)
);

