-- Query: Currently on loan (not returned)
SELECT m.name AS member, b.title AS book, l.due_date
FROM loan l
JOIN member m ON l.member_id = m.member_id
JOIN book   b ON l.book_id   = b.book_id
WHERE l.returned IS NULL;
